3	const readStdin = (): Promise<string> =>
4	  new Promise((resolve, reject) => {
5	    let data = "";
6	    process.stdin.setEncoding("utf8");
7	    process.stdin.on("data", (chunk) => {
8	      data += chunk;
9	    });
10	    process.stdin.on("end", () => resolve(data));
11	    process.stdin.on("error", reject);
12	  });
13	
14	const main = async (): Promise<void> => {
15	  const input = JSON.parse(await readStdin());
16	  const output = run(input);
17	  process.stdout.write(JSON.stringify(output) + "\n");
18	};
19	
20	main().catch((err: Error) => {
21	  process.stderr.write(`${err.message}\n`);
22	  process.exit(1);
23	});
